mapper.select:
SELECT DISTINCT T1.ID AS COURSE_ID , T3.ID AS NOTICE_ID , T3.TITLE , T3.INS_ID AS WRITER , T3.INS_DT AS CREATED_AT FROM COURSES T1 INNER JOIN LECTURES T2 ON T1.ID = T2.COURSE_ID INNER JOIN NOTICES T3 ON T3.INS_DT BETWEEN T2.START_DT AND T2.END_DT WHERE T1.ID = #{courseId}
AND T3.TITLE LIKE CONCAT('%', #{req.keyword}, '%')
AND T3.CONTENT LIKE CONCAT('%', #{req.keyword}, '%')
AND T3.INS_ID LIKE CONCAT('%', #{req.keyword}, '%')
AND (T3.TITLE LIKE CONCAT('%', #{req.keyword}, '%') OR T3.CONTENT LIKE CONCAT('%', #{req.keyword}, '%'))
ORDER BY T3.ID DESC LIMIT #{req.size} OFFSET #{req.offset}
